function parseCSV(csvText) {
  const lines = csvText.trim().split(/\r?\n/);
  const headers = lines[0].split(",").map(h => h.replace(/^"|"$/g, "").trim());

  return lines.slice(1).map(line => {
    const values = [];
    let current = "";
    let insideQuotes = false;

    for (let i = 0; i < line.length; i++) {
      const char = line[i];

      if (char === '"') {
        insideQuotes = !insideQuotes;
      } else if (char === "," && !insideQuotes) {
        values.push(current.trim());
        current = "";
      } else {
        current += char;
      }
    }

    values.push(current.trim());

    const row = {};
    headers.forEach((header, index) => {
      row[header] = values[index]?.replace(/^"|"$/g, "") ?? "";
    });

    return row;
  });
}

function toNumber(value) {
  const num = Number(String(value).replace(/,/g, ""));
  return Number.isFinite(num) ? num : 0;
}

function isValidDate(value) {
  const date = new Date(value);
  return value && !Number.isNaN(date.getTime());
}

const csvText = $input.first().json.data || $input.first().json.body || "";
const rows = parseCSV(csvText);

if (!rows.length) {
  throw new Error("No rows found in Google Sheet CSV.");
}

// IMPORTANT FIX:
// Do not blindly take rows[rows.length - 1].
// Instead, ignore blank/invalid rows and choose latest valid dated market row.
const validRows = rows.filter(row => {
  return (
    isValidDate(row.date) &&
    String(row.nifty_close || "").trim() !== "" &&
    String(row.nifty_change_pct || "").trim() !== "" &&
    String(row.banknifty_close || "").trim() !== "" &&
    String(row.banknifty_change_pct || "").trim() !== "" &&
    String(row.fii_net_cr || "").trim() !== "" &&
    String(row.dii_net_cr || "").trim() !== "" &&
    String(row.india_vix || "").trim() !== "" &&
    String(row.advance_count || "").trim() !== "" &&
    String(row.decline_count || "").trim() !== "" &&
    String(row.put_call_ratio || "").trim() !== ""
  );
});

if (!validRows.length) {
  throw new Error("No valid dated market rows found in Google Sheet CSV.");
}

validRows.sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());

const latest = validRows[validRows.length - 1];

const advanceCount = toNumber(latest.advance_count);
const declineCount = toNumber(latest.decline_count);
const totalBreadth = advanceCount + declineCount;
const marketBreadthRatio = declineCount > 0 ? Number((advanceCount / declineCount).toFixed(2)) : 0;

const niftyChange = toNumber(latest.nifty_change_pct);
const bankNiftyChange = toNumber(latest.banknifty_change_pct);
const fiiNet = toNumber(latest.fii_net_cr);
const diiNet = toNumber(latest.dii_net_cr);
const indiaVix = toNumber(latest.india_vix);
const pcr = toNumber(latest.put_call_ratio);

let riskScore = 30;

if (niftyChange < -0.75) riskScore += 15;
if (bankNiftyChange < -0.75) riskScore += 15;
if (fiiNet < -1500) riskScore += 20;
if (indiaVix > 16) riskScore += 20;
if (marketBreadthRatio < 0.75) riskScore += 15;
if (pcr < 0.9) riskScore += 10;

riskScore = Math.min(riskScore, 100);

let riskLevel = "Low";
if (riskScore >= 70) {
  riskLevel = "High";
} else if (riskScore >= 45) {
  riskLevel = "Medium";
}

const flowDivergence =
  fiiNet < 0 && diiNet > 0
    ? "FII selling was partially or fully absorbed by DII buying."
    : fiiNet > 0 && diiNet < 0
    ? "FII buying returned while DII flow was negative."
    : "Institutional flows were broadly aligned or neutral.";

const breadthTone =
  marketBreadthRatio > 1.2
    ? "Positive"
    : marketBreadthRatio < 0.8
    ? "Negative"
    : "Neutral";

const result = {
  success: true,
  project: "FundFlowOps",
  message: "Market KPI calculation completed successfully.",
  latest_date: latest.date,
  report_type: "daily",
  risk_score: riskScore,
  risk_level: riskLevel,
  kpis: {
    nifty_close: toNumber(latest.nifty_close),
    nifty_change_pct: niftyChange,
    banknifty_close: toNumber(latest.banknifty_close),
    banknifty_change_pct: bankNiftyChange,
    fii_net_cr: fiiNet,
    dii_net_cr: diiNet,
    india_vix: indiaVix,
    advance_count: advanceCount,
    decline_count: declineCount,
    market_breadth_ratio: marketBreadthRatio,
    top_sector: latest.top_sector || "",
    weak_sector: latest.weak_sector || "",
    put_call_ratio: pcr
  },
  analysis: {
    flow_divergence: flowDivergence,
    breadth_tone: breadthTone,
    notes: latest.notes || ""
  },

  // Debug fields to verify correct row selection
  rows_processed: rows.length,
  valid_rows_processed: validRows.length,
  selected_latest_date: latest.date,
  raw_latest_row: latest
};

return [
  {
    json: result
  }
];

function normalizeChoice(value, allowed, fallback) {
  const raw = String(value || "").trim().toLowerCase();
  const match = allowed.find(item => item.toLowerCase() === raw);
  return match || fallback;
}

function getInsertedReport() {
  const items = $input.all().map(item => item.json);

  // Case 1: Supabase returned one inserted row as one item
  if (items.length === 1 && items[0]?.id) {
    return items[0];
  }

  // Case 2: Supabase returned an array inside one item
  if (items.length === 1 && Array.isArray(items[0])) {
    return items[0][0];
  }

  // Case 3: Supabase returned multiple rows/items
  const flatItems = items.flatMap(item => Array.isArray(item) ? item : [item]);
  const report = flatItems.find(item => item && item.id);

  return report || null;
}

const insertedReport = getInsertedReport();

if (!insertedReport || !insertedReport.id) {
  throw new Error("No report id returned from Supabase Insert Report node.");
}

const reportId = insertedReport.id;

const parsedOutput = $("Parse Unified AI JSON v2").first().json;
const aiReport = parsedOutput.ai_report || {};

const aiSignals = Array.isArray(aiReport.signals)
  ? aiReport.signals
  : Array.isArray(parsedOutput.signals)
  ? parsedOutput.signals
  : [];

const fallbackSignals = [
  {
    signal_title: "No major standalone anomaly detected",
    severity: "Low",
    signal_type: "general",
    explanation: "The current market data did not produce a major standalone anomaly based on the available KPI inputs.",
    suggested_action: "Continue monitoring institutional flows, volatility, index movement, and market breadth."
  }
];

const sourceSignals = aiSignals.length > 0 ? aiSignals : fallbackSignals;

const signalPayloads = sourceSignals.slice(0, 5).map(signal => {
  return {
    report_id: reportId,

    signal_title:
      signal.signal_title ||
      signal.title ||
      "Untitled market signal",

    severity: normalizeChoice(
      signal.severity,
      ["Low", "Medium", "High"],
      "Medium"
    ),

    signal_type: normalizeChoice(
      signal.signal_type,
      ["flow", "volatility", "breadth", "sector", "index", "general"],
      "general"
    ),

    explanation:
      signal.explanation ||
      "No detailed explanation was provided by the AI agent.",

    suggested_action:
      signal.suggested_action ||
      "Review this signal manually before using it in stakeholder communication."
  };
});

return [
  {
    json: {
      report_id: reportId,
      saved_report: insertedReport,
      signal_payloads: signalPayloads
    }
  }
];

function collectSavedSignals() {
  const inputItems = $input.all().map(item => item.json);

  // Case 1: Supabase returned array inside a single item
  if (inputItems.length === 1 && Array.isArray(inputItems[0])) {
    return inputItems[0];
  }

  // Case 2: Supabase returned each signal as separate item
  return inputItems.flatMap(item => Array.isArray(item) ? item : [item]);
}

const savedSignals = collectSavedSignals();

const preparedSignalsNode = $("Prepare Supabase Signals Payload").first().json;
const parsedOutput = $("Parse Unified AI JSON v2").first().json;

const savedReport = preparedSignalsNode.saved_report;
const aiReport = parsedOutput.ai_report || {};

if (!savedReport || !savedReport.id) {
  throw new Error("Saved report data not found. Check Prepare Supabase Signals Payload node.");
}

const finalResponse = {
  success: true,
  project: "FundFlowOps",
  stage: "AI report and signals saved to Supabase successfully",

  report_id: savedReport.id,
  report_date: savedReport.report_date,
  report_type: savedReport.report_type,

  headline: savedReport.headline,
  market_summary: savedReport.market_summary,
  stakeholder_summary: savedReport.stakeholder_summary,

  risk_level: savedReport.risk_level,
  risk_score: savedReport.risk_score,

  status: savedReport.status,
  source: savedReport.source,
  model_used: savedReport.model_used,
  created_at: savedReport.created_at,

  kpis: parsedOutput.kpis || {},
  deterministic_analysis: parsedOutput.deterministic_analysis || {},

  ai_report: aiReport,

  saved_signals_count: savedSignals.length,
  saved_signals: savedSignals
};

return [
  {
    json: finalResponse
  }
];

