function value(v) {
  return v === undefined || v === null || v === "" ? "—" : v;
}

function moneyCr(v) {
  const n = Number(v);
  if (!Number.isFinite(n)) return "—";
  return `${n >= 0 ? "+" : "-"}₹${Math.abs(n)} Cr`;
}

function pct(v) {
  const n = Number(v);
  if (!Number.isFinite(n)) return "—";
  return `${n}%`;
}

function list(items) {
  if (!Array.isArray(items) || items.length === 0) return "—";
  return items.map(item => `• ${item}`).join("\n");
}

