const geminiResponse = $json;
const kpiData = $("Calculate Market KPIs").first().json;

let aiText =
  geminiResponse?.candidates?.[0]?.content?.parts?.[0]?.text || "";

if (!aiText) {
  aiText = "{}";
}

let aiReport = {};

try {
  aiText = aiText
    .replace(/```json/gi, "")
    .replace(/```/g, "")
    .trim();

  const firstBrace = aiText.indexOf("{");
  const lastBrace = aiText.lastIndexOf("}");

  if (firstBrace >= 0 && lastBrace > firstBrace) {
    aiText = aiText.substring(firstBrace, lastBrace + 1);
  }

  aiReport = JSON.parse(aiText);

} catch (error) {

  // Fallback report
  aiReport = {
    report_date:
      kpiData.latest_date ||
      new Date().toISOString().slice(0,10),

    report_type: "daily",

    headline:
      "FundFlowOps Market Intelligence Report",

    market_summary:
      "Fallback report generated because AI JSON formatting failed.",

    stakeholder_summary:
      "Market intelligence generated using deterministic KPI calculations.",

    risk_level:
      kpiData.risk_level || "Medium",

    risk_score:
      Number(kpiData.risk_score) || 50,

    signals: [],

    risk_analysis: {
      risk_score:
        Number(kpiData.risk_score) || 50,

      risk_level:
        kpiData.risk_level || "Medium"
    },

    market_regime_analysis: {
      market_regime:
        "Mixed/Neutral Market",

      confidence: 50
    }
  };
}

return [
